/* Nav: dropdown (Guías) + hamburger (mobile) + auto-hide on scroll (UI only) */
(() => {
  const header = document.querySelector('.header');
  if (!header) return;

  const nav = header.querySelector('.nav');
  const navToggle = header.querySelector('.nav-toggle');

  // --- Mobile menu (hamburger)
  const closeMenu = () => {
    if (!nav || !navToggle) return;
    nav.classList.remove('is-open');
    navToggle.setAttribute('aria-expanded', 'false');
    header.classList.remove('menu-open');
  };

  const openMenu = () => {
    if (!nav || !navToggle) return;
    nav.classList.add('is-open');
    navToggle.setAttribute('aria-expanded', 'true');
    header.classList.add('menu-open');
  };

  const toggleMenu = () => {
    if (!nav || !navToggle) return;
    if (nav.classList.contains('is-open')) {
      closeMenu();
      closeDropdown();
    } else {
      closeDropdown();
      openMenu();
    }
  };

  // Safety init: never start with open menu on mobile.
  if (window.matchMedia('(max-width: 860px)').matches) {
    closeMenu();
  }

  if (nav && navToggle) {
    navToggle.addEventListener('click', (e) => {
      e.preventDefault();
      toggleMenu();
    });

    // Close when clicking a link inside the menu (mobile)
    nav.addEventListener('click', (e) => {
      const a = e.target.closest('a');
      if (a && nav.classList.contains('is-open')) {
        closeMenu();
        closeDropdown();
      }
    });

    // Close on outside click (only when open)
    document.addEventListener('click', (e) => {
      if (!nav.classList.contains('is-open')) return;
      if (!header.contains(e.target)) {
        closeMenu();
        closeDropdown();
      }
    });

    // Close on Escape
    document.addEventListener('keydown', (e) => {
      if (e.key !== 'Escape') return;
      closeMenu();
      closeDropdown();
    });

    // Close on resize back to desktop
    window.addEventListener('resize', () => {
      if (window.matchMedia('(min-width: 861px)').matches) {
        closeMenu();
        closeDropdown();
      }
    });
  }

  // --- Dropdown: Guías
  const dropdown = header.querySelector('.dropdown');
  const dropdownToggle = dropdown ? dropdown.querySelector('.nav-dropdown') : null;
  const REQUIRED_GUIDES = [
    { href: '/guia/como-calcular-base-reguladora-paro.html', label: 'Cómo calcular la base reguladora del paro' },
    { href: '/guia/reanudar-paro-despues-de-trabajar.html', label: 'Reanudar el paro después de trabajar' },
    { href: '/guia/gastos-deducibles-autonomos-iva-irpf.html', label: 'Gastos deducibles de autónomos (IVA e IRPF)' }
  ];

  const ensureGuideLinks = () => {
    if (!dropdown) return;
    const menu = dropdown.querySelector('.dropdown-menu');
    if (!menu) return;

    const existing = new Set(
      Array.from(menu.querySelectorAll('a[href]')).map((a) => a.getAttribute('href'))
    );
    const hr = menu.querySelector('hr');

    REQUIRED_GUIDES.forEach((guide) => {
      if (existing.has(guide.href)) return;
      const link = document.createElement('a');
      link.href = guide.href;
      link.setAttribute('role', 'menuitem');
      link.textContent = guide.label;
      if (hr) {
        menu.insertBefore(link, hr);
      } else {
        menu.appendChild(link);
      }
      existing.add(guide.href);
    });
  };

  ensureGuideLinks();

  const closeDropdown = () => {
    if (!dropdown || !dropdownToggle) return;
    dropdown.classList.remove('open');
    dropdownToggle.setAttribute('aria-expanded', 'false');
  };

  const openDropdown = () => {
    if (!dropdown || !dropdownToggle) return;
    dropdown.classList.add('open');
    dropdownToggle.setAttribute('aria-expanded', 'true');
  };

  if (dropdown && dropdownToggle) {
    dropdownToggle.addEventListener('click', (e) => {
      e.preventDefault();
      const isOpen = dropdown.classList.contains('open');
      isOpen ? closeDropdown() : openDropdown();
    });

    document.addEventListener('click', (e) => {
      if (!dropdown.contains(e.target)) closeDropdown();
    });
  }

  // --- Auto-hide on scroll (disabled while menu open)
  let lastY = window.scrollY || 0;
  let ticking = false;
  const threshold = 8;          // ignore micro scroll
  const minShowY = 40;          // always show near top
  const minDeltaToToggle = 14;  // avoid jitter

  const onScroll = () => {
    const y = window.scrollY || 0;
    const delta = y - lastY;

    // Don't hide while menu is open
    if (header.classList.contains('menu-open')) {
      header.classList.remove('is-hidden');
      lastY = y;
      return;
    }

    // Always show at very top
    if (y <= minShowY) {
      header.classList.remove('is-hidden');
      lastY = y;
      return;
    }

    if (Math.abs(delta) < threshold) return;

    if (delta > minDeltaToToggle) {
      header.classList.add('is-hidden');
      closeDropdown();
    } else if (delta < -minDeltaToToggle) {
      header.classList.remove('is-hidden');
    }

    lastY = y;
  };

  window.addEventListener('scroll', () => {
    if (!ticking) {
      window.requestAnimationFrame(() => {
        onScroll();
        ticking = false;
      });
      ticking = true;
    }
  }, { passive: true });

})();
